import type { Metadata } from "next";
import TransitSearchClient from "./TransitSearchClient";

export const metadata: Metadata = {
  title: "経路検索結果 | 乗換案内",
  description: "新宿 → 横浜 の経路検索結果。早い・安い・楽で比較し、駅ごとの乗換と運賃を確認できます。",
};

// Server Component shell. All interactive UI (function props: onValueChange,
// formatValue, onSelect) lives inside the "use client" TransitSearchClient,
// so `next build` stays green.
export default function TransitSearchPage() {
  return (
    <main className="min-h-screen bg-background text-foreground">
      <TransitSearchClient />
    </main>
  );
}

// Realistic 乗換案内 / 経路検索 fixture data.
// 新宿 → 横浜 を例にした、実在の路線・駅・種別・運賃。

export type SortKey = "fast" | "cheap" | "easy";

/** 路線の識別子。色は data-driven なので CSS 変数ではなく実色で持つ（路線カラーは固定値の世界）。 */
export interface LineMeta {
  /** 路線名（例: JR山手線） */
  name: string;
  /** ラインカラー（公式の路線カラーに近い HEX） */
  color: string;
  /** 路線記号・略称（例: JY / M / F） */
  symbol?: string;
}

/** 経路の 1 区間（乗車レグ）または乗換（徒歩）レグ。 */
export interface Leg {
  kind: "ride" | "transfer";
  // --- ride ---
  line?: LineMeta;
  /** 種別（各駅停車 / 快速 / 急行 / 特急 …） */
  kindLabel?: string;
  /** 方面（〜行 / 〜方面） */
  direction?: string;
  fromStation?: string;
  toStation?: string;
  /** 発時刻 "HH:MM" */
  depTime?: string;
  /** 着時刻 "HH:MM" */
  arrTime?: string;
  /** 発ホーム（例: 3番線） */
  depPlatform?: string;
  /** 着ホーム */
  arrPlatform?: string;
  /** 乗車時間（分） */
  rideMin?: number;
  /** 通過/停車駅数のヒント */
  stopsHint?: string;
  /** 区間運賃（IC, 円） */
  fareIc?: number;
  /** 遅延（分）。0 / 未設定 = 定刻 */
  delayMin?: number;
  // --- transfer ---
  /** 徒歩（分） */
  walkMin?: number;
  /** 乗換メモ（例: 同一ホーム / ホーム移動あり） */
  transferNote?: string;
}

export interface RouteOption {
  id: string;
  depTime: string;
  arrTime: string;
  /** 所要（分） */
  totalMin: number;
  /** 乗換回数 */
  transfers: number;
  /** 運賃 IC（円） */
  fareIc: number;
  /** 運賃 きっぷ（円） */
  fareTicket: number;
  /** 総距離（km） */
  distanceKm: number;
  /** at-a-glance ラインストリップに出す路線（乗車レグの順） */
  lineStrip: LineMeta[];
  /** おすすめタグ */
  tags: Array<"fastest" | "cheapest" | "fewest" | "recommended" | "easy">;
  /** この経路に影響する運行情報があるか */
  hasDelay?: boolean;
  /** 詳細レグ */
  legs: Leg[];
}

export interface ServiceAlert {
  id: string;
  severity: "delay" | "suspended" | "info";
  line: string;
  message: string;
}

// --- 路線カラー定義（実在カラーに近い） ---
export const LINES = {
  yamanote: { name: "JR山手線", color: "#9acd32", symbol: "JY" },
  shonanShinjuku: { name: "JR湘南新宿ライン", color: "#e21f26", symbol: "JS" },
  saikyo: { name: "JR埼京線", color: "#00ac9b", symbol: "JA" },
  chuoRapid: { name: "JR中央線快速", color: "#f15a22", symbol: "JC" },
  marunouchi: { name: "東京メトロ丸ノ内線", color: "#e60012", symbol: "M" },
  fukutoshin: { name: "東京メトロ副都心線", color: "#9c5e31", symbol: "F" },
  toyoko: { name: "東急東横線", color: "#da0442", symbol: "TY" },
  keio: { name: "京王線", color: "#cf1063", symbol: "KO" },
  odakyu: { name: "小田急小田原線", color: "#0079c2", symbol: "OH" },
