export const SERVICE_ALERTS: ServiceAlert[] = [
  {
    id: "a1",
    severity: "delay",
    line: "JR湘南新宿ライン",
    message: "人身事故の影響で、上下線に最大10分の遅れが出ています。（10:42 更新）",
