];

export const SORT_TABS: Array<{ key: SortKey; label: string; hint: string }> = [
  { key: "fast", label: "早い", hint: "所要時間順" },
  { key: "cheap", label: "安い", hint: "運賃が安い順" },
  { key: "easy", label: "楽", hint: "乗換が少ない順" },
];

export const TAG_LABELS: Record<RouteOption["tags"][number], string> = {
  fastest: "最速",
  cheapest: "最安",
  fewest: "乗換少",
  recommended: "おすすめ",
  easy: "楽",
};

export function sortRoutes(routes: RouteOption[], key: SortKey): RouteOption[] {
  const copy = [...routes];
  switch (key) {
    case "fast":
      return copy.sort((a, b) => a.totalMin - b.totalMin);
    case "cheap":
      return copy.sort((a, b) => a.fareIc - b.fareIc);
    case "easy":
      return copy.sort((a, b) => a.transfers - b.transfers || a.totalMin - b.totalMin);
  }
}

"use client";

import * as React from "react";
import {
  IconArrowsUpDown,
  IconChevronRight,
  IconWalk,
  IconClock,
  IconArrowsRightLeft,
  IconAlertTriangle,
  IconCircleCheck,
} from "@tabler/icons-react";

import {
  Card,
  Badge,
  Tag,
  Button,
  Separator,
  SearchInput,
  Select,
  Alert,
  AlertTitle,
  AlertDescription,
  AmountBreakdown,
  Tabs,
  TabsList,
  TabsTrigger,
  VStack,
  HStack,
} from "@gunjo/ui";

import {
  ROUTES,
  SERVICE_ALERTS,
  SEARCH,
  SORT_TABS,
  TAG_LABELS,
  sortRoutes,
  type RouteOption,
  type LineMeta,
  type Leg,
  type SortKey,
} from "./data";

const yen = (n: number) => `${n.toLocaleString("ja-JP")}円`;

/* ------------------------------------------------------------------ */
/* 路線カラーチップ — 路線記号を色付きで。@gunjo/ui に line-color の概念が     */
/* 無いので手書き。Badge は token カラー固定で任意 HEX を載せられない。        */
/* ------------------------------------------------------------------ */
function LineChip({ line, size = "sm" }: { line: LineMeta; size?: "sm" | "md" }) {
  const dim = size === "md" ? "h-6 min-w-6 px-1.5 text-xs" : "h-5 min-w-5 px-1 text-[10px]";
  return (
    <span
      className={`inline-flex items-center justify-center rounded font-bold leading-none text-white ${dim}`}
      style={{ backgroundColor: line.color }}
      aria-hidden="true"
    >
      {line.symbol ?? line.name.slice(0, 2)}
    </span>
  );
}

/* at-a-glance ラインストリップ: 🟢山手線 → 🔴丸ノ内線 */
function LineStrip({ lines }: { lines: LineMeta[] }) {
  return (
    <span className="flex flex-wrap items-center gap-1" aria-label={`経由路線: ${lines.map((l) => l.name).join("、")}`}>
      {lines.map((l, i) => (
        <React.Fragment key={`${l.name}-${i}`}>
          {i > 0 && <IconChevronRight className="h-3 w-3 shrink-0 text-muted-foreground" aria-hidden="true" />}
          <span className="inline-flex items-center gap-1">
            <LineChip line={l} />
            <span className="text-xs text-foreground">{l.name.replace(/^(JR|東京メトロ|東急|京王|小田急)/, "")}</span>
          </span>
        </React.Fragment>
      ))}
    </span>
  );
}

const TAG_VARIANT: Record<RouteOption["tags"][number], React.ComponentProps<typeof Badge>["variant"]> = {
  fastest: "info",
  cheapest: "success",
  fewest: "secondary",
  recommended: "warning",
  easy: "secondary",
};

/* ------------------------------------------------------------------ */
/* 経路候補カード — tappable な result card。@gunjo/ui に result-card /        */
/* 検索結果リストの primitive が無いので Card を手で組み立てる。                */
/* ------------------------------------------------------------------ */
function RouteCard({
  route,
  selected,
  onSelect,
}: {
  route: RouteOption;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <Card
      className={
        "overflow-hidden p-0 transition-colors " +
        (selected ? "border-primary ring-1 ring-primary" : "hover:border-foreground/30")
      }
    >
      <button
        type="button"
        onClick={onSelect}
        aria-pressed={selected}
        aria-label={`${SEARCH.from}発 ${route.depTime} → ${SEARCH.to}着 ${route.arrTime}、所要${route.totalMin}分、乗換${route.transfers}回、IC ${yen(route.fareIc)}`}
        className="w-full cursor-pointer rounded-lg p-4 text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
      >
        <VStack gap={2}>
          {/* タグ行 */}
          {(route.tags.length > 0 || route.hasDelay) && (
            <HStack gap={1} className="flex-wrap">
              {route.tags.map((t) => (
                <Badge key={t} variant={TAG_VARIANT[t]}>
                  {TAG_LABELS[t]}
                </Badge>
              ))}
              {route.hasDelay && (
                <Badge variant="destructive" icon={<IconAlertTriangle />}>
                  遅延あり
                </Badge>
              )}
            </HStack>
          )}

          {/* 時刻 + 所要 */}
          <HStack justify="between" align="end" className="flex-wrap gap-y-1">
            <div className="flex items-baseline gap-2">
              <span className="text-2xl font-bold tabular-nums tracking-tight text-foreground">
                {route.depTime}
              </span>
              <IconChevronRight className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
              <span className="text-2xl font-bold tabular-nums tracking-tight text-foreground">
                {route.arrTime}
              </span>
            </div>
            <div className="text-right">
              <div className="text-sm font-semibold text-foreground">
                {Math.floor(route.totalMin / 60) > 0 && `${Math.floor(route.totalMin / 60)}時間`}
                {route.totalMin % 60}分
              </div>
              <div className="text-base font-bold tabular-nums text-foreground">
                {yen(route.fareIc)}
                <span className="ml-0.5 text-[10px] font-normal text-muted-foreground">IC</span>
              </div>
            </div>
          </HStack>

          {/* メタ行: 乗換・距離 */}
          <HStack gap={3} className="flex-wrap text-xs text-muted-foreground">
            <span className="inline-flex items-center gap-1">
              <IconArrowsRightLeft className="h-3.5 w-3.5" aria-hidden="true" />
              乗換 {route.transfers}回
            </span>
            <span className="tabular-nums">{route.distanceKm.toFixed(1)}km</span>
          </HStack>

          <Separator />

          {/* at-a-glance ラインストリップ */}
          <LineStrip lines={route.lineStrip} />
        </VStack>
      </button>
    </Card>
  );
}

/* ------------------------------------------------------------------ */
/* 経路詳細 leg-by-leg — RouteStops が delivery 用で route line / 種別 / 番線 /  */
/* 路線カラーを持てないため、駅↕区間の交互レイアウトを手書き。                 */
/* ------------------------------------------------------------------ */
function StationNode({
  name,
  time,
  platform,
  emphasis,
}: {
  name: string;
  time?: string;
  platform?: string;
  emphasis?: boolean;
}) {
  return (
    <div className="flex items-center gap-3">
      <span
        className={
          "z-10 h-3 w-3 shrink-0 rounded-full border-2 bg-background " +
          (emphasis ? "border-foreground" : "border-muted-foreground")
        }
        aria-hidden="true"
      />
      <div className="flex min-w-0 flex-1 items-baseline justify-between gap-2">
        <span className={"truncate " + (emphasis ? "text-base font-bold text-foreground" : "font-medium text-foreground")}>
          {name}
        </span>
        <span className="flex shrink-0 items-baseline gap-2 text-sm tabular-nums">
          {platform && <span className="text-xs text-muted-foreground">{platform}</span>}
          {time && <span className="font-semibold text-foreground">{time}</span>}
        </span>
      </div>
    </div>
  );
}

function RideLeg({ leg }: { leg: Leg }) {
  if (!leg.line) return null;
  return (
    <div className="relative flex gap-3 py-1">
      {/* 路線カラーの縦バー */}
      <div className="flex w-3 justify-center">
        <span className="w-1 flex-1 rounded-full" style={{ backgroundColor: leg.line.color }} aria-hidden="true" />
      </div>
      <div className="min-w-0 flex-1 py-2">
        <HStack gap={2} className="flex-wrap items-center">
          <LineChip line={leg.line} size="md" />
          <span className="text-sm font-semibold text-foreground">{leg.line.name}</span>
          {leg.kindLabel && <Tag variant="outline" size="sm">{leg.kindLabel}</Tag>}
          {leg.delayMin ? (
            <Badge variant="destructive" icon={<IconClock />}>
              約{leg.delayMin}分遅れ
            </Badge>
          ) : null}
        </HStack>
        <div className="mt-1 flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-muted-foreground">
          {leg.direction && <span>{leg.direction}</span>}
          {typeof leg.rideMin === "number" && <span className="tabular-nums">{leg.rideMin}分乗車</span>}
          {typeof leg.fareIc === "number" && <span className="tabular-nums">{yen(leg.fareIc)}</span>}
        </div>
        {leg.stopsHint && <div className="mt-0.5 text-xs text-muted-foreground">{leg.stopsHint}</div>}
      </div>
    </div>
  );
}

function TransferLeg({ leg }: { leg: Leg }) {
  return (
    <div className="flex gap-3 py-1">
      <div className="flex w-3 justify-center">
        <span className="w-px flex-1 border-l border-dashed border-border" aria-hidden="true" />
      </div>
      <div className="flex min-w-0 flex-1 items-center gap-2 py-1.5 text-xs text-muted-foreground">
        <IconWalk className="h-4 w-4 shrink-0" aria-hidden="true" />
        <span className="font-medium text-foreground">乗換 徒歩{leg.walkMin}分</span>
        {leg.transferNote && <span className="truncate">／ {leg.transferNote}</span>}
      </div>
    </div>
  );
}

function RouteDetail({ route }: { route: RouteOption }) {
  // 駅↕区間の交互列を組み立てる。
  const rides = route.legs.filter((l) => l.kind === "ride");
  const fareLines = rides.map((leg, i) => ({
    label: `${leg.fromStation} → ${leg.toStation}`,
    amount: leg.fareIc ?? 0,
    note: leg.line?.name,
    key: i,
  }));

  return (
    <VStack gap={4}>
      <section aria-label="経路の詳細" className="rounded-lg border bg-card p-4">
        <h3 className="mb-3 text-sm font-semibold text-foreground">
          経路詳細（{SEARCH.from} → {SEARCH.to}）
        </h3>
        <div className="flex flex-col">
          {route.legs.map((leg, i) => {
            if (leg.kind === "transfer") {
              return <TransferLeg key={`t-${i}`} leg={leg} />;
            }
            const isFirstRide = i === route.legs.findIndex((l) => l.kind === "ride");
            return (
              <React.Fragment key={`leg-${i}`}>
                <StationNode
                  name={leg.fromStation!}
                  time={leg.depTime}
                  platform={leg.depPlatform}
                  emphasis={isFirstRide}
                />
                <RideLeg leg={leg} />
                {/* 最後の ride の着駅 */}
                {i === route.legs.map((l) => l.kind).lastIndexOf("ride") && (
                  <StationNode name={leg.toStation!} time={leg.arrTime} platform={leg.arrPlatform} emphasis />
                )}
              </React.Fragment>
            );
          })}
        </div>
      </section>

      {/* 運賃まとめ — AmountBreakdown（formatValue を渡すので client 境界内で安全） */}
      <section aria-label="運賃まとめ" className="rounded-lg border bg-card p-4">
        <h3 className="mb-3 text-sm font-semibold text-foreground">運賃まとめ</h3>
        <AmountBreakdown
          formatValue={yen}
          lines={fareLines.map((l) => ({ label: l.label, amount: l.amount, note: l.note }))}
          total={{ label: "運賃 合計（IC）", amount: route.fareIc }}
          formula={`きっぷ ${yen(route.fareTicket)} ／ 距離 ${route.distanceKm.toFixed(1)}km`}
        />
        <p className="mt-3 text-xs text-muted-foreground">
          ※ 定期区間が登録されている場合、運賃はさらに割引されます。
        </p>
      </section>
    </VStack>
  );
}

/* ------------------------------------------------------------------ */
/* 運行情報アラート                                                          */
/* ------------------------------------------------------------------ */
function ServiceAlerts() {
  return (
    <VStack gap={2} aria-label="運行情報">
      {SERVICE_ALERTS.map((a) => {
        if (a.severity === "info") {
          return (
            <Alert key={a.id} variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
              <AlertTitle>{a.line}</AlertTitle>
              <AlertDescription>{a.message}</AlertDescription>
            </Alert>
          );
        }
        return (
          <Alert key={a.id} variant={a.severity === "suspended" ? "destructive" : "warning"}>
            <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
            <AlertTitle>
              {a.line}：{a.severity === "suspended" ? "運転見合わせ" : "遅延"}
            </AlertTitle>
            <AlertDescription>{a.message}</AlertDescription>
          </Alert>
        );
      })}
    </VStack>
  );
}

/* ------------------------------------------------------------------ */
/* 検索条件ヘッダー                                                          */
/* ------------------------------------------------------------------ */
function SearchHeader({
  from,
  to,
  onSwap,
  onFrom,
  onTo,
}: {
  from: string;
  to: string;
  onSwap: () => void;
  onFrom: (v: string) => void;
  onTo: (v: string) => void;
}) {
  return (
    <Card className="gap-3 p-4">
      <div className="flex items-stretch gap-2">
        <VStack gap={2} className="min-w-0 flex-1">
          <div>
            <label className="mb-1 block text-xs font-medium text-muted-foreground" htmlFor="from-input">
              出発
            </label>
            <SearchInput id="from-input" value={from} onValueChange={onFrom} placeholder="出発駅" aria-label="出発駅" />
          </div>
          <div>
            <label className="mb-1 block text-xs font-medium text-muted-foreground" htmlFor="to-input">
              到着
            </label>
            <SearchInput id="to-input" value={to} onValueChange={onTo} placeholder="到着駅" aria-label="到着駅" />
          </div>
        </VStack>
        <div className="flex items-center">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onSwap}
            aria-label="出発駅と到着駅を入れ替える"
          >
            <IconArrowsUpDown className="h-4 w-4" aria-hidden="true" />
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-2">
        <Select label="日時の基準" defaultValue={SEARCH.basis} aria-label="日時の基準">
          <option value="出発">出発</option>
          <option value="到着">到着</option>
          <option value="始発">始発</option>
          <option value="終電">終電</option>
        </Select>
        <Select label="経由" defaultValue="" aria-label="経由駅">
          <option value="">指定なし</option>
          <option value="渋谷">渋谷</option>
          <option value="武蔵小杉">武蔵小杉</option>
        </Select>
      </div>
      <p className="text-xs text-muted-foreground">
        <span className="font-medium text-foreground">{SEARCH.datetime}</span> {SEARCH.basis}
      </p>
    </Card>
  );
}

/* ------------------------------------------------------------------ */
/* ルート                                                                   */
/* ------------------------------------------------------------------ */
export default function TransitSearchClient() {
  const [from, setFrom] = React.useState(SEARCH.from);
  const [to, setTo] = React.useState(SEARCH.to);
  const [sort, setSort] = React.useState<SortKey>("fast");
  const [selectedId, setSelectedId] = React.useState<string>(ROUTES[0].id);

  const swap = () => {
    setFrom(to);
    setTo(from);
  };

  const sorted = React.useMemo(() => sortRoutes(ROUTES, sort), [sort]);
  const selected = React.useMemo(() => ROUTES.find((r) => r.id === selectedId) ?? ROUTES[0], [selectedId]);

  return (
    <div className="mx-auto w-full max-w-screen-sm px-4 pb-16 pt-4 sm:pt-6">
      <header className="mb-4">
        <h1 className="text-lg font-bold text-foreground">乗換案内</h1>
        <p className="text-sm text-muted-foreground">
          {from} → {to} の経路
        </p>
      </header>

      <VStack gap={4}>
        <SearchHeader from={from} to={to} onSwap={swap} onFrom={setFrom} onTo={setTo} />

        <ServiceAlerts />

        {/* 並び順タブ */}
        <div>
          <Tabs value={sort} onValueChange={(v) => setSort(v as SortKey)} className="border-0">
            <TabsList className="w-full">
              {SORT_TABS.map((t) => (
                <TabsTrigger key={t.key} value={t.key} className="flex-1" aria-label={`${t.label}（${t.hint}）`}>
                  {t.label}
                </TabsTrigger>
              ))}
            </TabsList>
          </Tabs>
          <p className="mt-1.5 px-1 text-xs text-muted-foreground" aria-live="polite">
            {SORT_TABS.find((t) => t.key === sort)?.hint}・{sorted.length}件
          </p>
        </div>

        {/* 経路候補リスト */}
        <section aria-label="経路候補">
          <VStack gap={3}>
            {sorted.map((route) => (
              <RouteCard
                key={route.id}
                route={route}
                selected={route.id === selectedId}
                onSelect={() => setSelectedId(route.id)}
              />
            ))}
          </VStack>
        </section>

        <Separator />

        {/* 選択した経路の詳細 */}
        <section aria-label="選択中の経路" aria-live="polite">
          <h2 className="mb-3 text-base font-bold text-foreground">
            選択中の経路：{selected.depTime} → {selected.arrTime}
          </h2>
          <RouteDetail route={selected} />
        </section>
      </VStack>
    </div>
  );
}
